from langgraph.graph import END
from vex import PolicyVerifier

vex_node = PolicyVerifier(policy="ecommerce-compliance")

def merge_cart_state(state):
    # Parallel branches might corrupt state here
    return vex_node(state)

class EcommerceGraph(StateGraph):
    def __init__(self):
        super().__init__(...)
        self.add_node("recommendations", self.recommendations_node)
        self.add_node("pricing", self.pricing_node)
        self.add_node("vex_check", merge_cart_state)  # After parallel merge
        self.add_edge("recommendations", "vex_check")
        self.add_edge("pricing", "vex_check")
        self.add_edge("vex_check", "human_review" if needs_review else END)

    def compile(self):
        return self._compile(checkpointer=MemorySaver())

graph = EcommerceGraph().compile()
